import{_ as a,o as i,c as t,ag as e}from"./chunks/framework.ePeAWSvT.js";const p=JSON.parse('{"title":"底盘维修指南","description":"","frontmatter":{},"headers":[],"relativePath":"tech/mechanical/chassis-maintenance.md","filePath":"tech/mechanical/chassis-maintenance.md"}'),r={name:"tech/mechanical/chassis-maintenance.md"};function o(n,l,d,h,s,c){return i(),t("div",null,[...l[0]||(l[0]=[e('<h1 id="底盘维修指南" tabindex="-1">底盘维修指南 <a class="header-anchor" href="#底盘维修指南" aria-label="Permalink to &quot;底盘维修指南&quot;">​</a></h1><p>底盘是机器人的基础，定期维护和检查非常重要。</p><h2 id="定期检查项目" tabindex="-1">定期检查项目 <a class="header-anchor" href="#定期检查项目" aria-label="Permalink to &quot;定期检查项目&quot;">​</a></h2><h3 id="视觉检查-每次使用后" tabindex="-1">视觉检查 (每次使用后) <a class="header-anchor" href="#视觉检查-每次使用后" aria-label="Permalink to &quot;视觉检查 (每次使用后)&quot;">​</a></h3><ul><li>[ ] 检查所有螺钉是否松动</li><li>[ ] 查看底盘是否有裂纹</li><li>[ ] 检查轮子是否磨损或损坏</li><li>[ ] 确认传送带张力正确</li></ul><h3 id="功能测试-每周" tabindex="-1">功能测试 (每周) <a class="header-anchor" href="#功能测试-每周" aria-label="Permalink to &quot;功能测试 (每周)&quot;">​</a></h3><ul><li>[ ] 测试所有4个车轮是否正常转动</li><li>[ ] 检查前进、后退、转弯功能</li><li>[ ] 验证编码器读数准确</li><li>[ ] 测试差速驱动平衡性</li></ul><h3 id="深度检查-每月" tabindex="-1">深度检查 (每月) <a class="header-anchor" href="#深度检查-每月" aria-label="Permalink to &quot;深度检查 (每月)&quot;">​</a></h3><ul><li>[ ] 清洁所有运动部件</li><li>[ ] 检查轴承状态</li><li>[ ] 验证电机连接牢固</li><li>[ ] 检查CAN总线连接</li></ul><h2 id="常见问题和解决方案" tabindex="-1">常见问题和解决方案 <a class="header-anchor" href="#常见问题和解决方案" aria-label="Permalink to &quot;常见问题和解决方案&quot;">​</a></h2><h3 id="问题1-某个轮子不转动" tabindex="-1">问题1: 某个轮子不转动 <a class="header-anchor" href="#问题1-某个轮子不转动" aria-label="Permalink to &quot;问题1: 某个轮子不转动&quot;">​</a></h3><p><strong>原因</strong>:</p><ul><li>电机断开连接</li><li>CAN总线故障</li><li>电机损坏</li><li>齿轮卡死</li></ul><p><strong>解决步骤</strong>:</p><ol><li>检查电源连接</li><li>验证CAN ID匹配</li><li>测试电机是否接收信号</li><li>检查齿轮或传动是否卡死</li><li>必要时更换电机</li></ol><h3 id="问题2-底盘运动方向错误" tabindex="-1">问题2: 底盘运动方向错误 <a class="header-anchor" href="#问题2-底盘运动方向错误" aria-label="Permalink to &quot;问题2: 底盘运动方向错误&quot;">​</a></h3><p><strong>原因</strong>:</p><ul><li>电机接线反向</li><li>代码中的倒序配置</li><li>编码器反向</li></ul><p><strong>解决步骤</strong>:</p><ol><li>检查接线顺序</li><li>验证WPILib代码中的电机设置</li><li>确认编码器方向配置</li></ol><h3 id="问题3-轮子打滑" tabindex="-1">问题3: 轮子打滑 <a class="header-anchor" href="#问题3-轮子打滑" aria-label="Permalink to &quot;问题3: 轮子打滑&quot;">​</a></h3><p><strong>原因</strong>:</p><ul><li>轮胎磨损</li><li>传送带松动</li><li>地面太光滑</li><li>PID控制不当</li></ul><p><strong>解决步骤</strong>:</p><ol><li>检查轮胎纹理</li><li>调整传送带张力</li><li>调整PID参数</li><li>必要时更换轮胎</li></ol><h2 id="维护及时表" tabindex="-1">维护及时表 <a class="header-anchor" href="#维护及时表" aria-label="Permalink to &quot;维护及时表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>任务</th><th>频率</th><th>预计时间</th><th>所需工具</th></tr></thead><tbody><tr><td>清洁检查</td><td>每周</td><td>15分钟</td><td>布, 刷子</td></tr><tr><td>螺钉紧固</td><td>每月</td><td>30分钟</td><td>螺丝刀, 扳手</td></tr><tr><td>轴承润滑</td><td>每月</td><td>20分钟</td><td>润滑油</td></tr><tr><td>深度检查</td><td>每季度</td><td>2小时</td><td>完整工具箱</td></tr></tbody></table><h2 id="安全提示" tabindex="-1">安全提示 <a class="header-anchor" href="#安全提示" aria-label="Permalink to &quot;安全提示&quot;">​</a></h2><p>⚠️ <strong>重要</strong>:</p><ul><li>维修前关闭所有电源</li><li>断开电池连接</li><li>禁用无线指令</li><li>使用适当的工具和个人防护装备</li><li>需要时向技术负责人寻求帮助</li></ul><h2 id="备件清单" tabindex="-1">备件清单 <a class="header-anchor" href="#备件清单" aria-label="Permalink to &quot;备件清单&quot;">​</a></h2><p>保持以下备件以备急用:</p><ul><li>预制轮轮胎 (4个)</li><li>Falcon 500电机 (2个)</li><li>传送带 (2条)</li><li>各种规格螺钉和螺帽</li><li>轴承 (若干)</li></ul><hr><p><strong>最后更新</strong>: 2024年2月</p>',35)])])}const b=a(r,[["render",o]]);export{p as __pageData,b as default};
